/**
 *
 * @param link
 * @param context
 * @param linkOptions
 * @return {Path}
 */
import { mathMax } from '../core/zc-constants';

function sankeyLinkBezier(context, link, linkOptions, minWidth = 0) {
    let halfWidth = mathMax(link.width / 2, minWidth / 2),
        x0 = link.source.x1,
        y0 = link.y0 - halfWidth,
        x1 = link.target.x0,
        y1 = link.y1 - halfWidth,
        padding = linkOptions.padding || 0;

    // add the padding in the offset
    x0 += padding;
    x1 -= padding;

    let width = mathMax(link.width, minWidth),
        controlPointX = (x0 + x1) / 2,
        controlPointX2 = (x0 + x1) / 2;

    if (x1 - x0 > width / 2) {
        if (y0 > y1) {
            controlPointX2 += width / 2;
        } else {
            controlPointX += width / 2;
        }
    }

    context.moveTo(x0, y0);
    context.bezierCurveTo(controlPointX, y0, controlPointX, y1, x1, y1);
    context.lineTo(x1, y1 + width);
    context.bezierCurveTo(controlPointX2, y1 + width, controlPointX2, y0 + width, x0, y0 + width);
    context.closePath();

    return context;
}

/**
 *
 * @param context
 * @param link
 * @param linkOptions
 * @param minWidth
 * @return {Path}
 */
function sankeyLinkLinear(context, link, linkOptions, minWidth = 0) {
    let halfWidth = mathMax(link.width / 2, minWidth / 2),
        x0 = link.source.x1,
        y0 = link.y0 - halfWidth,
        x1 = link.target.x0,
        y1 = link.y1 - halfWidth,
        h = mathMax(link.width, minWidth),
        padding = linkOptions.padding || 0;

    x0 += padding;
    x1 -= padding;

    context.moveTo(x0, y0);
    context.lineTo(x1, y1);
    context.lineTo(x1, y1 + h);
    context.lineTo(x0, y0 + h);
    context.closePath();

    // poly
    link._polypoints = [
        [x0, y0],
        [x1, y1],
        [x1, y1 + h],
        [x0, y0 + h]
    ];

    return context;
}

export { sankeyLinkBezier, sankeyLinkLinear };
